INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Portfolio and Project Management$q$, $q$Plan and track projects across a portfolio with Gantt views, dependencies, milestones, and critical path visibility.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Request and Work Intake Queues$q$, $q$Structured forms and queues let stakeholders submit requests, which are triaged and prioritized before entering the workflow.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Resource Management$q$, $q$Capacity planning and workload views help managers balance assignments across teams and avoid overallocation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Proofing and Digital Reviews$q$, $q$Built-in markup, versioning, and approval tools streamline creative review cycles for marketing and design assets.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Custom Workflows and Approvals$q$, $q$Configurable approval chains and automated status updates enforce governance across complex, multi-stage processes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Reporting and Dashboards$q$, $q$Real-time dashboards and custom reports give executives portfolio-level visibility into progress, budgets, and resourcing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Workfront Fusion Automation$q$, $q$A no-code automation layer connects Workfront to hundreds of external systems, including the broader Adobe Experience Cloud.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Enterprise Security and Governance$q$, $q$Role-based permissions, audit trails, and compliance controls support large, regulated organizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Deep portfolio and resource management suited to large, complex marketing and creative operations$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Strong proofing and approval workflows for creative review cycles$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Tight integration with Adobe Creative Cloud and the wider Adobe Experience Cloud$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Highly configurable to match complex, multi-stage governance processes$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Scales to very large enterprise deployments with thousands of users$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Pricing is not published and tends to be expensive relative to lighter-weight competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Steep learning curve and a more dated interface compared to newer work management tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Implementation and onboarding can be costly and time-consuming for large deployments$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Can feel like more structure than smaller teams or simple projects actually need$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Is Workfront the same as Adobe Workfront?$q$, $q$Yes. Workfront was an independent company until Adobe acquired it in December 2020 for about 1.5 billion US dollars; the product is now marketed as Adobe Workfront and sold as part of Adobe's Digital Experience Business Group.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$How much does Adobe Workfront cost?$q$, $q$Adobe does not publish list prices. Workfront is sold on custom, quote-based contracts across three tiers, Select, Prime, and Ultimate, with independent estimates placing typical costs around 49 to 99 US dollars per user per month billed annually, plus possible implementation fees.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Who is Workfront designed for?$q$, $q$Workfront is built primarily for marketing, creative, IT, and professional services teams inside mid-market and enterprise organizations that need to manage large portfolios of work with formal governance and approval processes.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Does Workfront integrate with Adobe Creative Cloud?$q$, $q$Yes. Workfront has native integration with Adobe Creative Cloud so creative teams can connect design files and assets directly to project tasks and review workflows.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$What is Workfront Fusion?$q$, $q$Workfront Fusion is Workfront's no-code automation and integration layer, letting teams connect Workfront to hundreds of external applications and automate multi-step processes without custom development.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$What was Workfront called before it was Workfront?$q$, $q$The company was originally founded in 2001 as AtTask and rebranded to Workfront in 2015 before being acquired by Adobe in 2020.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$What are the main alternatives to Workfront?$q$, $q$Common alternatives include Wrike, Asana, Monday.com, and Smartsheet, which generally offer lower-cost entry points but less marketing- and creative-specific functionality out of the box.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Does Workfront offer a free trial?$q$, $q$Adobe typically offers guided demos rather than a self-serve free trial for Workfront, reflecting its focus on larger, sales-assisted enterprise deployments.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Marketing Operations Management$q$, $q$Marketing teams use Workfront to manage campaign portfolios, intake requests, and creative review cycles from a single system.$q$, $q$Enterprise marketing and creative operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Creative Review and Approval$q$, $q$Creative teams use built-in proofing tools to collect markup and sign-off on design assets without switching tools.$q$, $q$In-house and agency creative teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Portfolio and Resource Planning$q$, $q$Program and PMO leaders use portfolio dashboards and resource views to balance capacity and prioritize work across departments.$q$, $q$PMO leaders and department heads at large enterprises$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Select$q$, $q$Custom (quote-based)$q$, $q$Annual contract$q$, NULL, $q$["Core project and task management","Collaboration tools","Basic reporting","Request queues"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Prime$q$, $q$Custom (quote-based)$q$, $q$Annual contract$q$, NULL, $q$["Everything in Select","Advanced strategic portfolio planning","Enhanced admin, security, and compliance controls","Expanded reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$Ultimate$q$, $q$Custom (quote-based)$q$, $q$Annual contract$q$, NULL, $q$["Everything in Prime","Workfront Fusion automation add-on","Advanced workflow optimization","Enterprise-scale governance"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$overview$q$, $q$What Is Workfront$q$, 2, ARRAY[$q$Workfront, sold today as Adobe Workfront, is a cloud-based work and project management platform purpose-built for marketing, creative, IT, and other cross-functional teams that need a single system to plan, prioritize, and execute work. It combines project and portfolio management, resource planning, and workflow automation so that leaders can see everything from high-level strategy down to individual tasks in one place.$q$, $q$The product has a long history: it launched in 2001 under the name AtTask, was substantially rebuilt in 2006, and was renamed Workfront in 2015 as it expanded beyond its original marketing operations niche into broader enterprise work management. Adobe acquired Workfront in a 1.5 billion US dollar deal that closed in December 2020, and the platform is now integrated into Adobe's Digital Experience Business Group alongside Adobe Experience Manager and Creative Cloud.$q$, $q$Because of its roots in marketing and creative operations, Workfront is especially strong at managing creative review and approval cycles, brand and campaign portfolios, and requests coming in from many stakeholders, while still supporting IT and operations use cases through custom workflows and enterprise governance controls.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Workfront centralizes project and portfolio management with configurable views such as Gantt-style timelines, boards, and lists, letting teams track dependencies, milestones, and critical paths across many concurrent projects.$q$, $q$Request and issue queues let stakeholders submit and prioritize work intake in a structured way, while resource management tools give managers visibility into team capacity and workload balancing across projects.$q$, $q$Built-in proofing and digital review tools support side-by-side markup and approval of creative assets, and Workfront Fusion adds no-code automation and integration with hundreds of external systems, including the wider Adobe Experience Cloud.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Adobe does not publish Workfront pricing publicly; all plans are quoted individually based on user count, selected modules, and support tier, and prospective customers must contact Adobe sales for a proposal.$q$, $q$The platform is sold in three packages, Select, Prime, and Ultimate, that layer on additional strategic portfolio planning, security, compliance, and automation capabilities as customers move up the tiers, with Ultimate adding the Workfront Fusion automation add-on.$q$, $q$Independent pricing trackers estimate real-world costs in the range of roughly 49 to 99 US dollars per user per month billed annually, with implementation, training, and data migration fees that can add another 5,000 to 20,000 US dollars depending on deployment size, making Workfront one of the pricier options in the work management category.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Employer of Record (EOR)$q$, $q$Hire employees compliantly in 160-plus countries without establishing a local legal entity.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Global Payroll$q$, $q$Automated payroll runs handle local tax withholding, statutory contributions, and payslips for each country.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Contractor Management$q$, $q$Onboard and pay international freelancers while managing worker misclassification risk.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$WorkDirect for Owned Entities$q$, $q$Payroll and HR administration for companies that already have their own foreign subsidiaries.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$WorkFlex Remote Work Compliance$q$, $q$Manage tax and immigration compliance for employees temporarily working from abroad.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Local Employment Contracts$q$, $q$Country-specific, compliant employment contracts drafted according to local labor law.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Benefits Administration$q$, $q$Statutory and supplementary benefits are administered locally to match each country's requirements.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Compliance Certification$q$, $q$Holds a Gold Certification from the IEC Group, an independent auditor of EOR compliance quality.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Broad country coverage spanning more than 160 markets$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Flat, transparent per-employee pricing on the core EOR product$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Multiple employment models (EOR, owned-entity payroll, contractor management, flexible remote work) under one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Independent Gold Certification from the IEC Group adds third-party validation of compliance quality$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Positioned as a lower-cost alternative to larger EOR players like Deel and Remote$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Smaller and less widely known than category leaders such as Deel and Remote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Per-employee EOR pricing can still add up quickly for companies scaling headcount in many countries$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Country-specific nuances in labor law mean turnaround times can vary by market$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Less independent public data available on company size and funding compared to larger competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$What does WorkMotion do?$q$, $q$WorkMotion is a global employment platform that lets companies hire, pay, and manage employees and contractors in more than 160 countries, primarily through its Employer of Record service.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$How much does WorkMotion's Employer of Record service cost?$q$, $q$WorkMotion's EOR plans start at approximately 499 euros per employee per month, a flat rate covering the employment contract, payroll, and statutory contributions.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Where is WorkMotion headquartered?$q$, $q$WorkMotion is headquartered in Berlin, Germany, where it was founded in 2020.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$What is the difference between WorkGlobal and WorkDirect?$q$, $q$WorkGlobal is WorkMotion's Employer of Record product for companies without a local entity, while WorkDirect provides payroll and HR administration for companies that already own a legal entity in that country.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Can WorkMotion manage contractors as well as employees?$q$, $q$Yes. WorkMotion offers a dedicated contractor management module for onboarding, paying, and maintaining compliance for international freelancers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$How many countries does WorkMotion support?$q$, $q$WorkMotion supports hiring in more than 160 countries through its own and partner legal entities.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$How does WorkMotion compare to Deel and Remote?$q$, $q$WorkMotion's EOR pricing is generally reported as lower than Deel's and Remote's list pricing, though all three compete on country coverage, speed, and compliance quality.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Is WorkMotion suitable for a single overseas hire?$q$, $q$Yes, WorkMotion's EOR service is commonly used by companies making their first hire in a new country before deciding whether to open a local entity.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Testing a New International Market$q$, $q$A company hires its first employee in a new country through WorkMotion's EOR service before committing to a local entity.$q$, $q$Companies expanding internationally$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Managing a Distributed Global Team$q$, $q$HR teams use WorkMotion to run payroll and manage compliance for employees spread across dozens of countries from one dashboard.$q$, $q$HR and People Ops teams at scaling companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Converting Contractors to Compliant Employees$q$, $q$Companies use WorkMotion to convert long-term contractors into properly classified local employees as regulations tighten.$q$, $q$Legal and compliance teams managing worker classification risk$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$WorkGlobal (Employer of Record)$q$, $q$From approximately EUR499 per employee per month$q$, $q$Monthly, per employee$q$, NULL, $q$["Local compliant employment contracts","Global payroll processing","Statutory benefits and tax withholding","Onboarding and offboarding support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$WorkDirect$q$, $q$Custom pricing$q$, $q$Monthly, per employee$q$, NULL, $q$["Payroll for owned foreign entities","HR administration","Compliance monitoring"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$Contractor Management$q$, $q$Custom pricing$q$, $q$Monthly, per contractor$q$, NULL, $q$["Contractor onboarding and payments","Worker classification risk management","Compliant contractor agreements"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$overview$q$, $q$What Is WorkMotion$q$, 2, ARRAY[$q$WorkMotion is a global employment platform that lets companies hire, pay, and manage employees and contractors in more than 160 countries without opening local legal entities in each market. It is best known for its Employer of Record, or EOR, service, which lets a client legally employ a worker abroad through WorkMotion's own or partner entities while WorkMotion handles the local employment contract, payroll, tax withholding, and statutory benefits.$q$, $q$The company was founded in 2020 in Berlin, Germany, initially under the name PeopleFlow, and is headquartered there today. WorkMotion has grown to serve companies expanding into new international markets, particularly those that want to test a market or hire a small number of people before committing to the cost of setting up a foreign subsidiary.$q$, $q$In addition to its EOR offering, WorkMotion provides tools for companies that already have their own foreign entities, for managing temporary remote-work-from-abroad arrangements, and for engaging and paying international contractors compliantly, giving customers a range of employment models under one platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$WorkGlobal, WorkMotion's flagship Employer of Record product, covers hiring in 160-plus countries through a network of owned and partner subsidiaries, handling local contracts, onboarding, payroll runs, tax filings, and statutory benefits administration.$q$, $q$WorkDirect supports companies that already hold their own foreign legal entities, providing payroll processing and HR administration without the EOR layer, while WorkFlex helps manage compliance for employees who want to work temporarily from another country.$q$, $q$A dedicated contractor management module lets companies onboard, pay, and stay compliant with international freelancers and contractors, including support for worker classification risk.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a0ac46b-2692-406a-b868-73e8c7b627db', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WorkMotion's core Employer of Record service starts at approximately 499 euros per employee per month, a single flat rate intended to cover the employment contract, payroll processing, and statutory contributions in the employee's country.$q$, $q$This positions WorkMotion's EOR pricing below some larger competitors, such as Deel's reported 599 to 899 US dollar per month tiers and Remote's roughly 645 euro per month rate, though exact comparisons depend on the country and services included.$q$, $q$Pricing for WorkDirect, WorkFlex, and contractor management is quoted separately based on the specific services and country coverage a customer needs, and companies should request a proposal directly from WorkMotion for an accurate quote.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Single Sign-On (SSO)$q$, $q$Unified SAML and OIDC API supporting Okta, Entra ID, Google Workspace, OneLogin, and more identity providers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Directory Sync (SCIM)$q$, $q$Automated user provisioning and deprovisioning synced from a customer's HR or identity directory.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$AuthKit$q$, $q$Prebuilt, themeable authentication UI covering passwords, social login, magic links, and multi-factor authentication.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$User Management$q$, $q$APIs for managing users, organizations, and multi-tenant relationships within an application.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Audit Logs$q$, $q$Structured, compliance-ready event logging that enterprise security teams can export and review.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Fine-Grained Authorization$q$, $q$Granular, relationship-based permission modeling for complex access control needs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Radar$q$, $q$Detects bot traffic, credential stuffing, and account-takeover attempts in real time.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Admin Portal$q$, $q$A self-service portal that lets enterprise customers configure their own SSO and directory connections.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Dramatically cuts the engineering time needed to become enterprise ready with SSO and SCIM$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Connection-based pricing scales predictably regardless of end-user count per enterprise customer$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Broad identity provider coverage reduces one-off integration work$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Widely adopted by leading AI and developer-tooling companies, signaling strong reliability at scale$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Free tier lets early-stage companies adopt core auth before enterprise features are needed$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Per-connection pricing can become expensive as a company signs many enterprise customers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Primarily aimed at B2B SaaS companies, offering less value for consumer-facing products$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Requires engineering integration work, unlike fully no-code identity tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Advanced modules like fine-grained authorization and Radar add further cost on top of SSO and Directory Sync$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$What problem does WorkOS solve?$q$, $q$WorkOS lets B2B SaaS companies add enterprise-required features like single sign-on, SCIM directory sync, audit logs, and role-based access control through APIs instead of building each one internally.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$How does WorkOS pricing work?$q$, $q$WorkOS charges a flat fee per enterprise customer connection for SSO and Directory Sync, starting at 125 US dollars per connection per month, with automatic volume discounts as more connections are added; AuthKit includes a free tier for monthly active users.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Who founded WorkOS and when?$q$, $q$WorkOS was founded in 2018 by Michael Grinich, who previously co-founded Nylas, and is headquartered in San Francisco, California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Which identity providers does WorkOS support?$q$, $q$WorkOS supports SAML and OIDC single sign-on with providers including Okta, Microsoft Entra ID, Google Workspace, OneLogin, JumpCloud, Ping Identity, and ADFS, plus SCIM directory sync with dozens of HR and identity directories.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$What is AuthKit?$q$, $q$AuthKit is WorkOS's prebuilt, themeable authentication UI that handles passwords, social login, magic links, multi-factor authentication, and multi-tenant organizations out of the box.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Which companies use WorkOS?$q$, $q$Publicly disclosed WorkOS customers include OpenAI, Anthropic, xAI, Cursor, Perplexity, Replit, and Vercel, among many other B2B SaaS and AI companies.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Does WorkOS have a free plan?$q$, $q$Yes. AuthKit offers a free tier based on monthly active users, letting companies use core authentication at no cost before they need paid SSO or Directory Sync connections.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$How is WorkOS different from Auth0 or Okta?$q$, $q$WorkOS focuses specifically on making B2B applications enterprise ready with connection-based pricing, while Auth0 and Okta offer broader identity platforms often priced per monthly active user or per employee seat.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Closing Enterprise Sales Deals$q$, $q$A SaaS startup integrates WorkOS SSO and Directory Sync to satisfy a large customer's security review requirements and close the deal.$q$, $q$B2B SaaS engineering and sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$AI Application Enterprise Readiness$q$, $q$AI companies use WorkOS to quickly add SOC 2-aligned authentication and access controls as they move upmarket from individual users to enterprise buyers.$q$, $q$AI-native startups selling to enterprises$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Centralizing Multi-Tenant User Management$q$, $q$Product teams use WorkOS User Management APIs to manage organizations, roles, and permissions across a multi-tenant application.$q$, $q$Product and platform engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["AuthKit authentication up to a monthly active user allowance","Passwordless and social login","Basic user management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$SSO and Directory Sync$q$, $q$From $125 per connection per month$q$, $q$Monthly, per enterprise connection$q$, NULL, $q$["SAML and OIDC single sign-on","SCIM directory sync","Automatic volume discounts at scale","Admin Portal for self-service setup"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$Enterprise Add-Ons$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Audit Logs","Fine-grained authorization","Radar bot and fraud detection","Dedicated support and SLAs"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$overview$q$, $q$What Is WorkOS$q$, 2, ARRAY[$q$WorkOS is a developer platform that lets business-to-business software companies add the security and identity features enterprise buyers demand, including single sign-on, directory sync, audit logs, and role-based access control, without building each of those systems from scratch.$q$, $q$Founded in 2018 by Michael Grinich and based in San Francisco, WorkOS was built around a common problem for growing SaaS startups: a promising enterprise deal stalls in security review because the buyer requires SAML SSO, SCIM provisioning into their identity provider, multi-factor authentication, and audit logging, features that can otherwise take months of engineering time to build correctly.$q$, $q$WorkOS has become especially popular with AI-native companies selling developer tools and applications into large enterprises, with publicly disclosed customers including OpenAI, Anthropic, xAI, Cursor, Perplexity, Replit, and Vercel.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Single Sign-On provides a unified API for SAML 2.0 and OpenID Connect that works across major identity providers such as Okta, Microsoft Entra ID, Google Workspace, OneLogin, JumpCloud, Ping Identity, and ADFS, so engineering teams write integration code once rather than per provider.$q$, $q$Directory Sync implements SCIM 2.0 to automate user provisioning and deprovisioning from a customer's identity directory, and AuthKit supplies a prebuilt, themeable authentication interface covering passwords, social login, magic links, multi-factor authentication, and multi-tenant organizations.$q$, $q$Additional modules include Audit Logs for compliance-ready event tracking, fine-grained authorization for granular permission models, and Radar for detecting bot traffic and account-takeover fraud, letting a single integration cover most enterprise-readiness requirements.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3455877b-59ac-4ce9-8371-d5101e680c67', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WorkOS uses a connection-based pricing model rather than charging per end user: each enterprise customer a company onboards through SSO or Directory Sync is billed as one connection, regardless of whether that customer has 10 or 10,000 employees behind it.$q$, $q$List pricing starts at 125 US dollars per connection per month, with automatic volume discounts as a company adds more enterprise customers, stepping down to roughly 100 US dollars per connection at 16 to 30 connections, 80 US dollars at 31 to 50, and 65 US dollars at 51 to 100.$q$, $q$AuthKit includes a generous free tier based on monthly active users, so early-stage companies can use core authentication for free and only start paying once they need enterprise SSO or directory sync for larger customers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Engagement Surveys$q$, $q$Configurable pulse, engagement, onboarding, and exit surveys measure employee sentiment continuously.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$People Analytics$q$, $q$Dashboards and benchmarking surface trends in engagement, retention risk, and manager effectiveness.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Peer Recognition$q$, $q$Employees and managers give values-based recognition tied to company culture in real time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Rewards Marketplace$q$, $q$Recognition points are redeemable through a global catalog of gift cards, merchandise, and donations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Goal Setting$q$, $q$Teams set and track individual and team goals connected to ongoing feedback and recognition.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Continuous Conversations$q$, $q$Structured check-in templates support regular manager-employee performance conversations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Manager Dashboards$q$, $q$Managers get team-level visibility into engagement scores, recognition activity, and goal progress.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Integrations$q$, $q$Connects with common HRIS, Slack, and Microsoft Teams to fit recognition and survey workflows into existing tools.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Combines engagement surveys and peer recognition in one platform rather than requiring separate vendors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Strong people analytics and benchmarking for tracking sentiment trends over time$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Global rewards catalog gives recognition real, flexible redemption value$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Well suited to mid-market and lower-enterprise employers consolidating HR tech$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Long product lineage (YouEarnedIt, HighGround, Kazoo) means mature, battle-tested survey and recognition features$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Pricing is not published and requires a sales conversation to get an accurate quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Company's multiple rebrands (YouEarnedIt to Kazoo to WorkTango) can create confusion when researching the product's history$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Full value requires adopting multiple modules, which can raise total cost versus single-purpose point solutions$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Less name recognition than category leaders such as Culture Amp or Lattice$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$What is WorkTango?$q$, $q$WorkTango is an employee experience platform combining engagement and pulse surveys, people analytics, and peer recognition and rewards in a single system.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Is WorkTango the same company as Kazoo?$q$, $q$Yes. Kazoo acquired the original, Toronto-based WorkTango in February 2022 and retired the Kazoo name in September 2022, adopting WorkTango as the unified brand for the combined company.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$How much does WorkTango cost?$q$, $q$WorkTango uses custom, quote-based pricing sold across Surveys and Insights, Recognition and Rewards, and Full Platform packages, with third-party estimates citing roughly 4 to 8 US dollars per employee per month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Where is WorkTango headquartered?$q$, $q$WorkTango is headquartered in Toronto, Ontario, Canada, with additional offices in Austin, Texas and Chicago, Illinois.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$What size companies use WorkTango?$q$, $q$WorkTango is generally positioned for mid-market and lower-enterprise employers, roughly 500 to 10,000 employees, that want surveys and recognition under one contract.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Can WorkTango replace a separate recognition tool?$q$, $q$Yes. WorkTango's Recognition and Rewards module includes peer recognition and a global rewards catalog, letting many customers consolidate a standalone recognition tool into the same platform as their surveys.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Does WorkTango offer performance management features?$q$, $q$WorkTango includes goal-setting and continuous conversation tools that link recognition and survey data to ongoing performance discussions, though it is primarily known for engagement surveys and recognition.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$What are WorkTango's main competitors?$q$, $q$WorkTango competes with employee experience and engagement platforms such as Culture Amp, Lattice, Bonusly, and Motivosity.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Employee Engagement Measurement$q$, $q$HR teams deploy recurring pulse and annual engagement surveys and use analytics to track sentiment and act on results.$q$, $q$HR and People Ops leaders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Peer Recognition Programs$q$, $q$Organizations roll out company-wide peer recognition tied to core values, redeemable through a global rewards catalog.$q$, $q$People teams building culture and retention programs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Manager Performance Conversations$q$, $q$Managers use goal tracking and continuous conversation templates to connect feedback and recognition to performance reviews.$q$, $q$Frontline and mid-level managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Surveys and Insights$q$, $q$Custom (quote-based)$q$, $q$Annual contract$q$, NULL, $q$["Engagement and pulse surveys","People analytics and benchmarking","Action planning tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Recognition and Rewards$q$, $q$Custom (quote-based)$q$, $q$Annual contract$q$, NULL, $q$["Peer-to-peer recognition","Values-based recognition tagging","Global rewards catalog"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$Full Platform$q$, $q$Custom (quote-based)$q$, $q$Annual contract$q$, NULL, $q$["Everything in Surveys and Insights and Recognition and Rewards","Goal setting","Continuous conversations","Unified people analytics"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$overview$q$, $q$What Is WorkTango$q$, 2, ARRAY[$q$WorkTango is an employee experience platform that brings together engagement and pulse surveys, people analytics, peer-to-peer recognition, and rewards in one connected system, letting HR teams both measure how employees feel and act on that feedback through recognition and goal-setting tools.$q$, $q$The company's history involves several mergers. YouEarnedIt, a peer recognition platform founded in Austin, Texas in 2011, acquired the survey and performance vendor HighGround in 2018 and rebranded as Kazoo in 2019. Kazoo then acquired the original, Toronto-based WorkTango in February 2022, and in September 2022 retired the Kazoo name in favor of the unified WorkTango brand used today.$q$, $q$WorkTango is headquartered in Toronto, Canada, with additional offices in Austin, Texas and Chicago, Illinois, and it is generally positioned toward mid-market and lower-enterprise employers looking to consolidate engagement surveys and recognition programs under a single vendor.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Surveys and Insights covers engagement, pulse, onboarding, and exit surveys along with people analytics dashboards and benchmarking data, giving HR teams a continuous read on employee sentiment across the organization.$q$, $q$Recognition and Rewards lets employees and managers send values-based peer recognition tied to company culture, which can be redeemed through a global rewards catalog spanning gift cards, merchandise, and charitable donations.$q$, $q$Goal management and continuous conversation tools connect day-to-day recognition and feedback to broader performance and development discussions, helping managers link engagement data to individual and team goals.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f693b898-12c0-4472-a7d3-8ed4219d2443', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WorkTango does not publish list pricing; the platform is sold on custom, quote-based contracts organized around three broad packages, commonly referred to as Surveys and Insights, Recognition and Rewards, and a combined Full Platform option.$q$, $q$Third-party pricing trackers estimate typical costs in the range of roughly 4 to 8 US dollars per employee per month, with the final price depending on employee count, selected modules, and contract length.$q$, $q$Because pricing is customized, prospective buyers should request a proposal directly from WorkTango to get an accurate quote based on their specific module mix and organization size.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$EverCache Performance Layer$q$, $q$Proprietary full-page and object caching designed to deliver sub-second load times from a global edge network.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$One-Click Staging$q$, $q$Spin up a staging copy of a site to test changes before pushing them to production.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Web Application Firewall and Malware Scanning$q$, $q$Automated daily scans and a WAF help block common exploits and detect compromised files early.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Git and SSH Developer Tools$q$, $q$Git-based deployment, SSH and SFTP access, and WP-CLI support fit WP Engine into standard developer workflows.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Free Premium Themes$q$, $q$Every plan includes free access to up to ten StudioPress themes built on the Genesis Framework.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$WooCommerce Hosting$q$, $q$A dedicated e-commerce hosting tier adds store-specific performance optimizations for checkout and search.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Local Development Sync$q$, $q$Integration with Local, WP Engine's free local WordPress development tool, streamlines the build-to-deploy workflow.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Isolated Hosting Containers$q$, $q$Each site runs in an isolated environment so other customers' traffic or issues cannot affect performance or security.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Strong, WordPress-specific performance through the proprietary EverCache caching layer$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Robust built-in security including WAF, malware scanning, and enforced two-factor authentication$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Developer-friendly workflow with Git, SSH, WP-CLI, and one-click staging$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Free premium Genesis Framework themes bundled with every plan$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Dedicated WooCommerce hosting tier for e-commerce-specific needs$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Pricing is higher than basic shared or generic cloud WordPress hosting$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Entry-level plans have relatively low monthly visit and storage caps compared to price$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Only hosts WordPress and WooCommerce sites, not a general-purpose hosting solution$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Enterprise pricing is fully custom and not transparent upfront$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$What is WP Engine?$q$, $q$WP Engine is a managed WordPress hosting company that handles server management, performance optimization, and security for WordPress and WooCommerce sites.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$How much does WP Engine cost?$q$, $q$WP Engine's Startup plan begins at roughly 30 US dollars per month billed annually, with Professional, Growth, Scale, and Core tiers scaling up to about 400 US dollars per month, and custom Enterprise pricing above that.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Who founded WP Engine and when?$q$, $q$WP Engine was founded in 2010 by Jason Cohen and is headquartered in Austin, Texas.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Does WP Engine support staging environments?$q$, $q$Yes, every WP Engine plan includes one-click staging environments for testing changes before deploying to production.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Can WP Engine host WooCommerce stores?$q$, $q$Yes, WP Engine offers a dedicated WooCommerce hosting tier with e-commerce-specific performance optimizations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$What is EverCache?$q$, $q$EverCache is WP Engine's proprietary caching technology that combines full-page and object caching to speed up WordPress page delivery from edge locations.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Does WP Engine include free themes?$q$, $q$Yes, WP Engine plans include free access to up to ten premium StudioPress themes built on the Genesis Framework.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$What are the main alternatives to WP Engine?$q$, $q$Common alternatives include Kinsta, Pantheon, Pressable, and Flywheel, which WP Engine itself acquired, all competing in the managed WordPress hosting space.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Agency Client Site Management$q$, $q$Digital agencies host and manage many client WordPress sites using staging, Git deployment, and centralized billing.$q$, $q$Web design and digital agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$High-Traffic Content Publishing$q$, $q$Media and content sites rely on EverCache and CDN integration to keep pages fast under heavy traffic.$q$, $q$Publishers and content-heavy businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$WooCommerce Store Hosting$q$, $q$Online retailers use WP Engine's dedicated WooCommerce tier for optimized checkout and store performance.$q$, $q$E-commerce businesses running WooCommerce$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Startup$q$, $q$About $30 per month$q$, $q$Monthly or annual (annual billing shown)$q$, NULL, $q$["1 site","25,000 monthly visits","10GB storage","Free CDN and SSL"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Professional$q$, $q$About $55 per month$q$, $q$Monthly or annual$q$, NULL, $q$["3 sites","75,000 monthly visits","15GB storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Growth$q$, $q$About $109 per month$q$, $q$Monthly or annual$q$, NULL, $q$["10 sites","150,000 monthly visits","20GB storage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Scale$q$, $q$About $276 per month$q$, $q$Monthly or annual$q$, NULL, $q$["30 sites","400,000 monthly visits","50GB storage"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Core$q$, $q$About $400 per month$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 150 sites","Isolated resources","99.99 percent uptime SLA"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom contract$q$, NULL, $q$["Fully customized architecture","Dedicated infrastructure","Premium support and SLAs"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$overview$q$, $q$What Is WP Engine$q$, 2, ARRAY[$q$WP Engine is a managed WordPress hosting provider that handles server management, performance tuning, and security for WordPress and WooCommerce sites, letting agencies, businesses, and publishers focus on building and running their sites rather than administering infrastructure.$q$, $q$The company was founded in 2010 by Jason Cohen and is headquartered in Austin, Texas, with additional offices around the world. Over time it has become one of the best-known names in managed WordPress hosting, acquiring competitors such as Flywheel and building a large ecosystem of agency partners.$q$, $q$WP Engine positions itself as a premium option that trades a higher price than basic shared hosting for WordPress-specific performance optimization, proactive security, and hands-on support, making it a common choice for agencies managing many client sites and businesses running high-traffic content or e-commerce sites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$EverCache, WP Engine's proprietary caching technology, combines full-page and object caching to serve WordPress pages quickly from edge locations, while integrated Cloudflare CDN support further reduces load times for visitors around the world.$q$, $q$Security features include a web application firewall, daily automated malware scanning, enforced two-factor authentication, and isolated hosting containers so that traffic spikes or vulnerabilities on other customers' sites do not affect a given site's performance or security.$q$, $q$Developer tools include one-click staging environments, Git-based deployment, SSH and SFTP access, WP-CLI support, and integration with Local, WP Engine's free local WordPress development app, plus free access to premium StudioPress Genesis Framework themes on every plan.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0ed951ec-77f0-4b46-b0d3-dc10cc9de347', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WP Engine's managed WordPress plans are tiered primarily by number of sites, monthly visits, and storage. The entry-level Startup plan starts at roughly 30 US dollars per month for one site with up to 25,000 monthly visits when billed annually.$q$, $q$Mid-tier plans scale up from there: Professional at about 55 US dollars per month, Growth at about 109 US dollars per month, and Scale at about 276 US dollars per month, each raising the number of sites, visits, and storage included.$q$, $q$The Core plan starts at about 400 US dollars per month and is aimed at high-traffic sites needing isolated resources and a 99.99 percent uptime service-level agreement, while Enterprise customers with the largest or most complex deployments receive fully custom-priced packages.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Gantt Charts and Dependencies$q$, $q$Build project timelines with drag-and-drop task dependencies and automatic critical path recalculation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Real-Time Dashboards$q$, $q$Configure dashboards from 20-plus widget types and share them with stakeholders outside the platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Resource Management$q$, $q$Visualize team workload and capacity to rebalance assignments across concurrent projects.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Proofing and Approvals$q$, $q$Collect markup, comments, and sign-off on creative assets directly inside project tasks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Custom Workflows and Fields$q$, $q$Configure workflows, statuses, and custom fields to match specific team processes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$AI Agents and Priority Inbox$q$, $q$Built-in AI features surface priority work and automate routine project updates on all plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$400+ Integrations$q$, $q$Connects with Slack, Microsoft Teams, Salesforce, Jira, GitHub, Tableau, and a deep, bidirectional Adobe Creative Cloud integration.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Time Tracking$q$, $q$Log time against tasks and projects for reporting on effort and billing.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Deep Gantt chart and dependency management rivaling dedicated scheduling tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Highly configurable, real-time dashboards with shareable external views$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$AI Agents and Priority Inbox included on all plans rather than sold as a paid add-on$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Very strong Adobe Creative Cloud integration for creative teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Free plan supports unlimited users for basic use cases$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Business and higher tiers can get expensive per user compared to lighter competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Feature depth and configurability create a steeper learning curve for new users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Resource management and proofing are locked behind the Business plan or higher$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Complex ownership history (Vista to Citrix and back to Vista) has occasionally raised questions about long-term product direction$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$What is Wrike used for?$q$, $q$Wrike is used for project and work management, including planning timelines with Gantt charts, tracking tasks, managing team workload, and reporting through dashboards.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$How much does Wrike cost?$q$, $q$Wrike has a free plan, a Team plan from 9.80 US dollars per user per month, a Business plan at about 24.80 US dollars per user per month, and custom-priced Enterprise and Pinnacle plans.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Who owns Wrike?$q$, $q$Wrike is currently an independent, privately held company backed by Vista Equity Partners and Evergreen Coast Capital, after being separated from Citrix Systems by May 2025.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$When was Wrike founded?$q$, $q$Wrike was founded in 2006 by Andrew Filev and is headquartered in San Jose, California.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Does Wrike include AI features?$q$, $q$Yes, as of January 2026 Wrike includes AI Agents and an AI Priority Inbox on all plans, including the free plan, at no additional cost.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Does Wrike integrate with Adobe Creative Cloud?$q$, $q$Yes, Wrike offers a deep, bidirectional integration with Adobe Creative Cloud that syncs design files with project tasks.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Is there a free version of Wrike?$q$, $q$Yes, Wrike offers a free plan with unlimited users, interactive Kanban boards, spreadsheets, and tables, suited to small teams and solopreneurs.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$What are Wrike's main competitors?$q$, $q$Wrike competes with Asana, Monday.com, Smartsheet, and Adobe Workfront in the work and project management category.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Marketing and Creative Project Management$q$, $q$Marketing and creative teams use Wrike's proofing tools and Adobe Creative Cloud integration to manage campaign production and review.$q$, $q$Marketing and creative teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Cross-Functional Portfolio Tracking$q$, $q$Operations and PMO teams use Gantt charts and dashboards to track multiple projects and dependencies across departments.$q$, $q$PMO leaders and operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Resource and Capacity Planning$q$, $q$Managers use workload views to balance task assignments and prevent overallocation across team members.$q$, $q$Team leads and resource managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Free$q$, $q$$0$q$, $q$Free forever$q$, NULL, $q$["Unlimited users","Kanban boards, spreadsheets and tables","Basic task management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Team$q$, $q$$9.80 per user per month$q$, $q$Annual billing$q$, NULL, $q$["Up to 25 users","Interactive Gantt charts","Custom item types","Automation"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Business$q$, $q$$24.80 per user per month$q$, $q$Annual billing$q$, NULL, $q$["Custom fields and workflows","Resource management","Proofing and approvals","Branded workspaces"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom contract$q$, NULL, $q$["Advanced security and admin controls","SSO and user provisioning","Scalable governance"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Pinnacle$q$, $q$Custom pricing$q$, $q$Custom contract$q$, NULL, $q$["Advanced analytics","Budgeting and locked spaces","Extended automation limits"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$overview$q$, $q$What Is Wrike$q$, 2, ARRAY[$q$Wrike is a cloud-based work and project management platform that helps cross-functional teams plan projects, track progress, and report on work through Gantt charts, dashboards, and resource management tools.$q$, $q$The company was founded in 2006 by Andrew Filev and is headquartered in San Jose, California. Its ownership has changed several times: Vista Equity Partners took a majority stake in 2018, Citrix Systems acquired the company in 2021 for about 2.25 billion US dollars, and Wrike was spun back out as an independent, Vista-backed company by May 2025 after Vista and Evergreen Coast Capital's acquisition of Citrix.$q$, $q$Wrike is used across marketing, creative, IT, and operations teams and is known for combining detailed project scheduling tools with flexible, real-time dashboards and a deep integration with Adobe Creative Cloud for review workflows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Gantt charts let teams build project timelines with drag-and-drop dependencies; Wrike automatically recalculates downstream task dates and highlights the critical path when a schedule changes.$q$, $q$Real-time dashboards support more than 20 widget types, including workload charts, budget burn, and task completion rates, and can be shared with external stakeholders who do not have Wrike accounts.$q$, $q$Resource management tools give managers a consolidated view of team workload, letting them switch between workload charts, Gantt views, and custom project views to balance capacity across projects; as of January 2026, AI Agents and an AI Priority Inbox are included on all plans at no extra cost.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Wrike offers a free plan aimed at solopreneurs and small teams, with unlimited users and interactive Kanban boards, spreadsheets, and tables.$q$, $q$The Team plan starts at 9.80 US dollars per user per month billed annually, while the Business plan costs about 24.80 US dollars per user per month and adds custom fields, custom workflows, item types, proofing and approvals, resource management, and monthly automations.$q$, $q$Enterprise and Pinnacle plans are priced on request and add advanced security, scalability, and governance features suited to large organizations with complex compliance needs.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$ActivityPub Federation$q$, $q$Blogs federate with Mastodon, Pleroma, and other Fediverse platforms so followers can subscribe without leaving their own network.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Distraction-Free Editor$q$, $q$A fast, auto-saving Markdown editor with live preview keeps the writing experience minimal and focused.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Self-Hosting$q$, $q$Fully open-source and free to install on your own server, with lightweight resource requirements down to a Raspberry Pi.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Multi-User Instances$q$, $q$Host many independent blogs with custom domains and themes under a single WriteFreely installation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Privacy by Design$q$, $q$No tracking scripts, ads, or engagement mechanics, aligning with the platform's privacy-first philosophy.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Custom Domains and Themes$q$, $q$Blogs can use their own domain names and customizable themes rather than a fixed platform look.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Markdown Support$q$, $q$Posts are written and stored in Markdown, making content portable and easy to migrate.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Hosted Alternatives$q$, $q$Write.as and WriteFreely.host offer managed hosting for people who do not want to run their own server.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Completely free and open-source, with no licensing cost to self-host$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Genuine ActivityPub federation connects blogs to the wider Fediverse and Mastodon audience$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Extremely lightweight and minimalist, runs even on a Raspberry Pi$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Strong privacy stance with no tracking, ads, or engagement-bait features$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Multi-user support makes it suitable for community and organizational blogs, not just individuals$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Self-hosting requires server administration knowledge and ongoing maintenance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Minimalist feature set lacks the themes, plugins, and monetization tools of platforms like WordPress$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Smaller community and ecosystem than mainstream blogging platforms means fewer themes and integrations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Federated audience reach depends on the broader Fediverse, which is smaller than centralized social platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$What is WriteFreely?$q$, $q$WriteFreely is a free, open-source, minimalist blogging platform that federates over ActivityPub, letting self-hosted blogs be followed from Mastodon and other Fediverse services.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Is WriteFreely free to use?$q$, $q$Yes, the WriteFreely software itself is free and open-source. Costs only arise if you use a paid hosted alternative like Write.as or pay for your own server.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Who created WriteFreely?$q$, $q$WriteFreely was created by developer Matt Baer, who first built the hosted service Write.as in 2015 and later open-sourced its underlying engine as WriteFreely in late 2018.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$What does ActivityPub federation mean for WriteFreely blogs?$q$, $q$It means people on Mastodon, Pleroma, and other ActivityPub-enabled platforms can follow, share, and interact with a WriteFreely blog's posts directly from their own platform.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Can WriteFreely host multiple blogs or writers?$q$, $q$Yes, WriteFreely supports multi-user instances so one installation can host many separate blogs with their own domains and themes.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$What are the system requirements to self-host WriteFreely?$q$, $q$WriteFreely is written in Go and designed to run efficiently on minimal hardware, including devices as small as a Raspberry Pi.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Is there a hosted version of WriteFreely for people who do not want to self-host?$q$, $q$Yes, Musing Studio offers Write.as for individual blogs and WriteFreely.host for community blogs, with hosted plans reported to start around 6 US dollars per month.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$How is WriteFreely different from WordPress?$q$, $q$WriteFreely is intentionally minimalist and federation-first, with a much smaller feature set than WordPress but native ActivityPub support that WordPress lacks without additional plugins.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Personal Fediverse Blogging$q$, $q$Individuals self-host a distraction-free blog that Mastodon users can follow directly through ActivityPub.$q$, $q$Independent bloggers and writers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Community and Organizational Publishing$q$, $q$Communities run a shared, multi-author WriteFreely instance for members to publish under one platform.$q$, $q$Online communities and small organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Privacy-Focused Publishing$q$, $q$Writers who want to avoid tracking, ads, and algorithmic feeds use WriteFreely for ad-free, distraction-free publishing.$q$, $q$Privacy-conscious writers and publishers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A (open-source software)$q$, NULL, $q$["Full source code on GitHub","Unlimited blogs and users on your own server","ActivityPub federation","No licensing fees"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Write.as Hosted$q$, $q$From about $6 per month$q$, $q$Monthly or annual$q$, NULL, $q$["Managed hosting, no server setup","Custom domain support","Basic blog with Write.as branding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$Write.as Pro$q$, $q$Custom (higher tier)$q$, $q$Monthly or annual$q$, NULL, $q$["Custom themes","Newsletters","Photo hosting","Up to three blogs"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$overview$q$, $q$What Is WriteFreely$q$, 2, ARRAY[$q$WriteFreely is a free and open-source blogging platform built specifically for the Fediverse, the decentralized network of social and publishing platforms connected by the ActivityPub protocol. It lets anyone run their own minimalist, self-hosted blog that can still be followed and shared by users on Mastodon and other Fediverse services.$q$, $q$The project traces back to Write.as, a privacy-focused hosted blogging service that developer Matt Baer launched in 2015. Baer later extracted the underlying engine and open-sourced it as WriteFreely in late 2018, giving anyone the ability to self-host the same software that powers Write.as.$q$, $q$WriteFreely is written in Go, runs efficiently on minimal hardware including a Raspberry Pi, and is maintained by Baer's small company, Musing Studio, which also operates the hosted Write.as and WriteFreely.host services for people who prefer not to self-host.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ActivityPub federation is WriteFreely's defining feature: posts published on a WriteFreely blog can be followed, liked, boosted, and commented on by users of Mastodon, Pleroma, and other ActivityPub-compatible platforms, extending a small blog's reach into the wider Fediverse.$q$, $q$The writing experience is deliberately minimalist, with a fast, auto-saving, distraction-free editor that supports Markdown and live preview, and no built-in notifications, algorithmic feed, or engagement metrics to distract writers or readers.$q$, $q$Multi-user support lets one WriteFreely instance host many separate blogs with custom domains and themes, making it suitable for communities, small publications, and organizations that want to run a shared but self-hosted blogging platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WriteFreely itself is free, open-source software that can be downloaded from GitHub and self-hosted on any server or virtual private server the operator controls, with no license fees.$q$, $q$Because self-hosting requires server administration knowledge, Musing Studio, the company behind WriteFreely, also offers managed hosted alternatives: Write.as for individual blogs and WriteFreely.host for community and multi-author blogs.$q$, $q$Hosted plans through Write.as are reported to start at around 6 US dollars per month, with higher tiers adding features like custom themes, newsletters, photo hosting, and support for multiple blogs or collaborators.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0eeb6217-8a67-456a-8643-6f5a58e0f979', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Palmyra Large Language Models$q$, $q$Writer's own proprietary LLM family powers writing, chat, and agent features instead of relying solely on third-party models.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Knowledge Graph$q$, $q$Connects company documents and data sources so AI output is grounded in enterprise-specific context.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$AI Agents$q$, $q$Configurable agents automate structured, multi-step business workflows beyond simple text generation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Brand Voice and Style Guide Enforcement$q$, $q$Ensures AI-generated content stays consistent with a company's tone, terminology, and compliance rules.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Prebuilt Templates and Apps$q$, $q$Ready-made templates and chat applications speed up common enterprise content and workflow tasks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Enterprise Security and Compliance$q$, $q$Built for regulated industries with data governance, access controls, and auditability features.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Content Generation at Scale$q$, $q$Supports high-volume marketing and communications content generation across teams and departments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Integrations$q$, $q$Connects with common enterprise systems and content platforms to fit into existing workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Owns its own Palmyra models rather than being a thin wrapper on third-party AI$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Knowledge Graph grounding improves accuracy and relevance for enterprise-specific content$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Strong focus on regulated industries with compliance and brand-governance features$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Backed by significant funding at a 1.9 billion US dollar valuation and a large roster of enterprise customers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$AI agents extend the platform beyond writing into broader business process automation$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Enterprise pricing is opaque and can be expensive for smaller organizations$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Primarily built for large enterprises, offering less value for individual users or very small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Owning proprietary models means feature parity with the latest general-purpose frontier models can lag at times$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Full value requires investment in Knowledge Graph setup and data integration, adding implementation effort$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$What makes Writer different from other AI writing tools?$q$, $q$Writer builds its own Palmyra large language models rather than relying solely on third-party APIs, and pairs them with a Knowledge Graph that grounds output in a company's own data, which most consumer AI writing tools do not offer.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Who founded Writer and when?$q$, $q$Writer was founded in 2020 by May Habib and Waseem AlShikh and is headquartered in San Francisco, California.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$How much does Writer cost?$q$, $q$Writer offers a Team plan reported at roughly 18 to 29 US dollars per user per month, while Enterprise plans are custom-priced based on scale and features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$What is Writer's Knowledge Graph?$q$, $q$The Knowledge Graph connects an organization's documents and data sources to Writer's models so generated content and answers are grounded in company-specific context rather than generic information.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Which companies use Writer?$q$, $q$Writer reports serving more than 250 enterprise customers, including Accenture, Intuit, L'Oreal, Salesforce, Uber, Vanguard, Mars, and Marriott.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$How much funding has Writer raised?$q$, $q$Writer has raised approximately 326 million US dollars in venture funding, including a 200 million US dollar Series C in November 2024 at a 1.9 billion US dollar valuation.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Is Writer suitable for regulated industries?$q$, $q$Yes, Writer specifically targets regulated industries such as financial services, healthcare, and insurance with compliance-oriented governance and grounding features.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Does Writer offer AI agents beyond writing assistance?$q$, $q$Yes, Writer's platform includes configurable AI agents that automate structured business workflows in addition to content generation.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Enterprise Marketing Content Generation$q$, $q$Marketing teams use Writer to generate on-brand content at scale while enforcing consistent tone and style across departments.$q$, $q$Enterprise marketing and communications teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Regulated Industry Compliance Writing$q$, $q$Financial services and healthcare organizations use Writer's Knowledge Graph to ground AI content in verified, company-specific data.$q$, $q$Compliance and legal teams in regulated industries$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Business Process Automation with AI Agents$q$, $q$Operations teams deploy Writer's AI agents to automate structured, multi-step internal workflows.$q$, $q$Enterprise operations and IT teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Team$q$, $q$Roughly $18 to $29 per user per month$q$, $q$Monthly or annual$q$, NULL, $q$["Palmyra model access","Writing and chat applications","Basic templates","Limited Knowledge Graph connectors"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["Full Knowledge Graph integration","AI agents","Advanced security and compliance controls","Dedicated support and onboarding"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$overview$q$, $q$What Is Writer$q$, 2, ARRAY[$q$Writer is an enterprise generative AI company that builds its own large language models, called Palmyra, rather than relying solely on third-party models, and combines them with a Knowledge Graph and an application layer of chat interfaces, templates, and AI agents to serve large organizations.$q$, $q$The company was founded in 2020 by May Habib and Waseem AlShikh and is headquartered in San Francisco, California. It has raised roughly 326 million US dollars in venture funding, including a 200 million US dollar Series C round in November 2024 that valued the company at 1.9 billion US dollars.$q$, $q$Writer positions itself specifically for regulated and large enterprise customers, reporting more than 250 enterprise customers including Accenture, Intuit, L'Oreal, Salesforce, Uber, Vanguard, Mars, and Marriott, and emphasizing accuracy, brand consistency, and auditability over general-purpose consumer AI writing tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Palmyra, Writer's proprietary family of large language models, powers the platform's writing, chat, and agent capabilities, giving Writer control over model behavior, cost, and fine-tuning that companies relying on third-party APIs do not have.$q$, $q$The Knowledge Graph connects an organization's own documents, data sources, and systems to the models, so generated content and answers are grounded in company-specific context rather than generic public information, which supports compliance and factual accuracy requirements.$q$, $q$AI agents and prebuilt templates let teams automate structured workflows, from marketing content generation to internal business processes, while style-guide and brand-voice controls keep AI-generated output consistent across a large organization.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Writer offers a Team plan intended for smaller groups, with pricing reported in the range of roughly 18 to 29 US dollars per user per month depending on the specific package and features included.$q$, $q$Enterprise plans are fully custom and quoted based on user count, modules, and data integration needs, with typical annual spend reported to range from around 10,000 to 50,000 US dollars for small teams, 75,000 to 250,000 US dollars for mid-market deployments, and above 500,000 US dollars for the largest enterprise rollouts.$q$, $q$Because pricing depends heavily on scale and which modules, such as Knowledge Graph connectors, agents, and specific Palmyra models, are included, prospective customers should request a proposal directly from Writer's sales team for an accurate quote.$q$]::text[], 2);
