-- Enrichment marathon batch: Workfront, WorkMotion, WorkOS, WorkTango, WP Engine, Wrike, writefreely, Writer

-- ── Workfront ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Adobe Workfront is an enterprise work management platform that helps marketing, creative, and cross-functional teams plan, execute, and report on projects and portfolios.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE($q$Pricing is custom and quote-based; third-party estimates place per-seat costs around $49 to $99 per user per month, billed annually$q$, starting_price),
  founded_year = COALESCE(2001, founded_year),
  company_size = COALESCE($q$Roughly 1,000 employees at the time of the Adobe acquisition in 2020; now operates as part of Adobe Inc.$q$, company_size),
  headquarters = COALESCE($q$Lehi, Utah, United States (part of Adobe Inc., headquartered in San Jose, California)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Workfront Review: Features, Pricing, and Alternatives (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Adobe Workfront helps marketing and creative teams manage projects, portfolios, and approvals, plus pricing tiers, features, pros and cons for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Workfront (marketed today as Adobe Workfront) is an enterprise work management and project management platform built for marketing, creative, IT, and other cross-functional teams that need to plan, prioritize, and track work at scale. The company was founded in 2001 in Utah by Scott Johnson under the name AtTask; the original platform was rewritten and relaunched in 2006, and the company rebranded from AtTask to Workfront in 2015. On November 9, 2020, Adobe announced it would acquire Workfront for approximately 1.5 billion US dollars, a deal that closed on December 7, 2020; at that time Workfront had roughly 4,000 customers and about 1,000 employees. Workfront is now sold as part of Adobe's Digital Experience Business Group and is commonly bundled or integrated with Adobe Experience Manager, Adobe Creative Cloud, and Adobe Workfront Fusion, its automation and integration layer. Core capabilities include centralized project and portfolio management, request and issue queues, resource and capacity management, Gantt-chart style timelines, custom workflows and approval chains, proofing and digital asset review, time tracking, reporting and dashboards, and enterprise-grade governance and security controls. Workfront is sold through three tiers, Select, Prime, and Ultimate, each unlocking more advanced portfolio planning, security and compliance, and workflow automation; Adobe does not publish list prices and instead quotes custom contracts based on user count, modules, and support level, though third-party analyses estimate typical costs in the 49 to 99 US dollar per user per month range when billed annually, plus implementation and onboarding fees that can run into the tens of thousands of dollars for larger deployments. The platform is aimed primarily at mid-market and enterprise marketing operations, creative operations, and professional services organizations rather than small teams, and it competes with tools such as Wrike, Asana, Monday.com, and Smartsheet, generally positioning itself as a heavier, more governance-focused system tailored to marketing and creative workflows with deep integration into the broader Adobe ecosystem. Notable strengths include robust portfolio-level reporting, approval and proofing workflows suited to creative review cycles, and native ties to Adobe Creative Cloud assets; commonly cited drawbacks include a steep learning curve, a dated interface relative to newer competitors, and pricing that is opaque and comparatively high for smaller teams.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'bec0d6fd-87d3-42f0-99a3-c8210c0e6b88';

