-- ── WorkMotion ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$WorkMotion is a Berlin-based global employment platform that lets companies hire, pay, and manage employees and contractors compliantly in more than 160 countries through Employer of Record services.$q$, short_description),
  pricing_model = COALESCE($q$usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Employer of Record plans start from around EUR499 per employee per month; contractor management and direct-entity modules are priced separately$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Berlin, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$WorkMotion Review: EOR Pricing, Features, and Alternatives (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$Explore WorkMotion's Employer of Record platform: global hiring in 160+ countries, pricing from EUR499 per employee per month, features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$WorkMotion is a Berlin, Germany-headquartered global employment technology company that helps businesses hire, pay, and manage employees and contractors in more than 160 countries without setting up local legal entities. The company was founded in 2020 in Berlin by Carsten Lebtig, Felix Steffens, and Karim Zaghloul, originally operating under the name PeopleFlow before rebranding to WorkMotion. WorkMotion's core product is an Employer of Record, or EOR, service delivered through a global network of owned and partner legal entities, so a client company can legally employ workers in a foreign country while WorkMotion handles local employment contracts, payroll, tax withholding, statutory benefits, and compliance with local labor law. Beyond its flagship WorkGlobal EOR product, WorkMotion offers WorkDirect for companies that already hold their own foreign legal entities and want payroll and HR administration without the EOR wrapper, WorkFlex for managing temporary work-from-abroad and remote work policies, and a contractor management module for engaging and paying international freelancers compliantly. Pricing for the core EOR service starts at approximately 499 euros per employee per month, a flat all-in rate that is intended to cover contract creation, payroll processing, and statutory contributions, positioning it below the list pricing of larger competitors such as Deel and Remote. WorkMotion has raised roughly 64 million US dollars in venture funding across three rounds and holds a Gold Certification from the IEC Group, an independent compliance auditor, which the company markets as evidence of its EOR quality and risk controls, a distinction it says makes it the first EOR provider to receive that certification globally. The platform is aimed at mid-market and enterprise companies expanding into new countries that want to test markets, hire specialized talent, or manage distributed teams without the cost and delay of entity establishment, and it competes directly with Deel, Remote, Papaya Global, and Oyster in the broader global employment and payroll category. Typical use cases include hiring a first employee in a new country before deciding whether to open a local entity, managing a small number of employees in markets too small to justify entity setup, and converting contractors to compliant local employees as regulations tighten around worker classification.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1a0ac46b-2692-406a-b868-73e8c7b627db';

