-- ── WorkOS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$WorkOS is a developer platform that adds enterprise-ready features such as single sign-on, SCIM directory sync, audit logs, and user management to B2B SaaS applications through a small set of APIs.$q$, short_description),
  pricing_model = COALESCE($q$usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free tier available through AuthKit; Single Sign-On and Directory Sync start at 125 US dollars per connection per month with automatic volume discounts$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$WorkOS Review: Pricing, Features, and Alternatives for Enterprise Auth (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn how WorkOS adds SSO, SCIM directory sync, and user management to SaaS apps, plus pricing from $125 per connection, features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$WorkOS is a developer-focused platform, founded in 2018 by Michael Grinich and headquartered in San Francisco, California, that gives business-to-business software companies a fast way to become enterprise ready. Rather than build single sign-on, directory sync, audit logging, and role-based access control from scratch for every enterprise customer, engineering teams integrate WorkOS's APIs and SDKs once and gain a unified layer that supports SAML 2.0 and OpenID Connect SSO across identity providers such as Okta, Microsoft Entra ID, Google Workspace, OneLogin, JumpCloud, Ping Identity, and ADFS, plus SCIM 2.0 directory sync for automated user provisioning and deprovisioning from directories including Okta, Entra ID, Google Workspace, BambooHR, and Rippling. WorkOS also offers AuthKit, a prebuilt, themeable authentication UI covering email and password, social login, magic links, multi-factor authentication, role-based access control, and multi-tenant organization support, along with Audit Logs, fine-grained authorization, and Radar for bot and fraud detection. WorkOS is widely used by AI-native and developer-tooling companies that need to sell into large, security-conscious enterprises quickly; publicly named customers include OpenAI, Anthropic, xAI, Cursor, Perplexity, Replit, Vercel, and Webflow. Pricing follows a connection-based usage model, a flat monthly fee per enterprise customer connected via SSO or Directory Sync, starting at 125 US dollars per connection per month with automatic volume discounts that reduce the per-connection price as a company connects more customers, for example roughly 100 US dollars per connection at 16 to 30 connections and roughly 65 US dollars per connection at 51 to 100 connections. A free tier is available through AuthKit's monthly active user allowance, letting early-stage companies use core authentication features at no cost before they need enterprise SSO. In 2026, WorkOS raised a 100 million US dollar Series C led by Meritech and Sapphire Ventures at a 2 billion US dollar valuation, reflecting rapid growth driven partly by demand from AI application companies. WorkOS competes with platforms like Auth0, Okta's developer products, FusionAuth, and Frontegg.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3455877b-59ac-4ce9-8371-d5101e680c67';

