-- ── WorkTango ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$WorkTango is an employee experience platform that combines engagement surveys and people analytics with peer recognition and rewards in a single system, formed from the 2022 merger of Kazoo and the original WorkTango.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$Custom, quote-based pricing; third-party estimates cite roughly 4 to 8 US dollars per user per month depending on which modules are included$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Toronto, Ontario, Canada (also maintains offices in Austin, Texas and Chicago, Illinois)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$WorkTango Review: Features, Pricing, and Alternatives (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$See how WorkTango combines engagement surveys, people analytics, and recognition and rewards, plus pricing, features, pros, cons, and FAQs for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$WorkTango is an employee experience platform that unifies engagement surveys, people analytics, goal setting, and peer-to-peer recognition and rewards in a single system, aimed at HR and people leaders who want to measure and improve how employees feel about their work. The current company is the product of a multi-step consolidation: YouEarnedIt, a peer recognition platform, was founded in Austin, Texas in 2011 and acquired HighGround, a performance management and pulse-survey vendor, in 2018 after both companies came under Vista Equity Partners ownership; the combined business rebranded as Kazoo in April 2019. In February 2022, Kazoo acquired the original WorkTango, a Toronto-based employee voice and engagement-survey company, and in September 2022 the combined company retired the Kazoo name and adopted WorkTango as its unified brand identity going forward. WorkTango is headquartered in Toronto, Ontario, Canada, and maintains additional offices in Austin, Texas and Chicago, Illinois, reflecting its layered acquisition history. The platform's core capabilities span three areas: Surveys and Insights, which covers engagement, pulse, and lifecycle surveys along with people analytics and benchmarking; Recognition and Rewards, which lets employees and managers give values-based peer recognition redeemable for a global rewards catalog; and goal-setting and continuous performance conversations that connect day-to-day recognition to broader performance management. WorkTango sells these capabilities as modular, quote-based packages, commonly summarized as Surveys and Insights, Recognition and Rewards, and a Full Platform bundle, with third-party trackers estimating typical per-user pricing in the range of roughly 4 to 8 US dollars per employee per month depending on which modules a customer selects and company size. The platform is generally positioned for mid-market and lower-enterprise employers, roughly 500 to 10,000 employees, that want engagement surveys and recognition under one vendor relationship rather than separate point solutions, and it competes with tools such as Culture Amp, Lattice, Bonusly, and Motivosity in the broader employee experience and engagement category.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f693b898-12c0-4472-a7d3-8ed4219d2443';

