-- ── Wrike ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Wrike is a cloud-based work and project management platform offering Gantt charts, real-time dashboards, resource management, and 400+ integrations for cross-functional teams.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; Team plan starts at 9.80 US dollars per user per month billed annually$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Jose, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Wrike Review: Pricing, Features, and Alternatives (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$Compare Wrike's project management plans and pricing from free to $24.80 per user per month, Gantt charts, dashboards, AI features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Wrike is a cloud-based work and project management platform founded in 2006 by Andrew Filev and headquartered in San Jose, California, used by cross-functional teams to plan, track, and report on projects. The platform's ownership has changed hands several times: Vista Equity Partners acquired a majority stake in 2018 at roughly an 800 million US dollar valuation, Citrix Systems then acquired Wrike from Vista for about 2.25 billion US dollars in 2021, and when Vista Equity Partners and Evergreen Coast Capital acquired Citrix and combined it with TIBCO Software in 2024, Wrike was separated back out as an independent, Vista-backed company, with the separation completing by May 2025. Wrike's core capabilities include Gantt chart-style timelines with dependency tracking and critical path calculation, real-time dashboards built from more than 20 configurable widget types, resource and workload management for balancing capacity across teams, custom fields and workflows, proofing and approval tools for creative and marketing review, and time tracking. As of January 2026, Wrike included AI Agents and an AI Priority Inbox across all plans at no additional cost, a move the company positioned against competitors that charge 20 to 40 US dollars per user per month extra for comparable AI add-ons. The platform connects to more than 400 external tools, including Slack, Microsoft Teams, Google Workspace, Salesforce, Jira, GitHub, Tableau, Power BI, and Marketo, with an especially deep, bidirectional integration with Adobe Creative Cloud. Wrike is sold on a tiered pricing model: a free plan for small teams with unlimited users and basic boards and tables, a Team plan starting at 9.80 US dollars per user per month billed annually, a Business plan at about 24.80 US dollars per user per month that adds resource management, custom workflows, and proofing, and custom-priced Enterprise and Pinnacle plans for larger organizations needing advanced security, scalability, and governance. Wrike competes broadly with Asana, Monday.com, Smartsheet, and Adobe Workfront in the work and project management category, generally differentiating on its Gantt chart depth, dashboard flexibility, and native creative-review workflow.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd4a5fa48-12d7-422f-9252-b7bea83b9ff4';

