-- ── writefreely ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$WriteFreely is a free, open-source, minimalist blogging platform written in Go that federates over ActivityPub, letting posts reach followers on Mastodon and other Fediverse services.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free to self-host; the hosted Write.as service built on WriteFreely starts at about 6 US dollars per month$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Small, independently maintained open-source project backed by Musing Studio, the small team led by creator Matt Baer$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$WriteFreely Review: Features, Self-Hosting, and Alternatives (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$Discover WriteFreely, the free open-source federated blogging platform for the Fediverse: features, self-hosting, pricing, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$WriteFreely is a free, open-source, minimalist blogging platform designed for the Fediverse, the decentralized social network built on the ActivityPub protocol. It was created by developer Matt Baer, who originally built the closed-source hosted blogging service Write.as in 2015 as a privacy-focused alternative to data-harvesting social platforms, then extracted and open-sourced its underlying engine as WriteFreely in late 2018. WriteFreely is written in Go, distributed on GitHub under an open-source license, and designed to run efficiently on minimal hardware, including a Raspberry Pi, installed either as a simple compiled binary or via Docker. The platform's defining feature is ActivityPub federation: any blog hosted on a WriteFreely instance can be followed, bookmarked, and shared by users on Mastodon, Pleroma, and other ActivityPub-compatible services, letting small, self-hosted blogs participate in a larger federated network rather than existing as isolated silos. WriteFreely deliberately omits algorithmic feeds, notifications, likes, and other engagement mechanics common to mainstream blogging and social platforms, instead offering a fast, auto-saving, distraction-free writing editor with Markdown support and live preview. It supports multi-user instances, so an organization or community can host many writers' blogs under one installation, each with custom domains, themes, and privacy settings, and it collects no tracking data or advertising by design. Because it is fully open-source, WriteFreely can be self-hosted for free on a server or VPS the operator controls, which is the primary way most technically inclined users and communities run it. For people who do not want to manage their own server, Matt Baer's company, Musing Studio, offers hosted alternatives: WriteFreely.host for starting a multi-author community blog, and Write.as for individual publishing, with hosted plans reported to start at roughly 6 US dollars per month. WriteFreely is commonly used by independent bloggers, small communities, and organizations that value data ownership, simplicity, and Fediverse participation over the features and lock-in of large commercial blogging platforms such as Medium or WordPress.com.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0eeb6217-8a67-456a-8643-6f5a58e0f979';

